import{pipe,asyncMap,asyncCollectArray,zip}from"@hyperjump/pact";import*as Browser from"@hyperjump/browser";import*as Instance from"../instance.js";import{Validation}from"../experimental.js";const id="https://json-schema.org/keyword/prefixItems",compile=(e,t)=>pipe(Browser.iter(e),asyncMap(e=>Validation.compile(e,t)),asyncCollectArray),interpret=(e,t,r)=>{if("array"!==Instance.typeOf(t))return!0;let p=!0,a=0;var i,o,l=Instance.length(t);for([i,o]of zip(e,Instance.iter(t))){if(a>=l)break;Validation.interpret(i,o,r)||(p=!1),a++}return p},simpleApplicator=!0,collectEvaluatedItems=(e,t,r)=>interpret(e,t,r)&&new Set(e.map((e,t)=>t));export default{id:id,compile:compile,interpret:interpret,simpleApplicator:simpleApplicator,collectEvaluatedItems:collectEvaluatedItems};